    @WebMethod
    public String processXMLData(String xmlPayload) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setIgnoringElementContentWhitespace(true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new ByteArrayInputStream(xmlPayload.getBytes()));
            
            return processDocument(document);
            
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new RuntimeException("Failed to parse XML payload", e);
        }
    }
    
    private String processDocument(Document document) {
        Element root = document.getDocumentElement();
        StringBuilder result = new StringBuilder();
        
        processElement(root, result, 0);
        
        return result.toString();
    }
    
    private void processElement(Element element, StringBuilder result, int depth) {
        String indent = "  ".repeat(depth);
        result.append(indent).append("<").append(element.getNodeName()).append(">\n");
        
        NodeList children = element.getChildNodes();
        for (int i = 0; i < children.getLength(); i++) {
            org.w3c.dom.Node node = children.item(i);
            
            if (node.getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                processElement((Element) node, result, depth + 1);
            } else if (node.getNodeType() == org.w3c.dom.Node.TEXT_NODE) {
                String text = node.getNodeValue().trim();
                if (!text.isEmpty()) {
                    result.append(indent).append("  ").append(text).append("\n");
                }
            }
        }
        
        result.append(indent).append("</").append(element.getNodeName()).append(">\n");
    }
    
    @WebMethod
    public ImportResult processDataImport(String xmlPayload) {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            
            DocumentBuilder builder = factory.newDocumentBuilder();
            Document document = builder.parse(new ByteArrayInputStream(xmlPayload.getBytes()));
            
            ImportResult result = new ImportResult();
            processImportData(document, result);
            
            return result;
            
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new RuntimeException("Failed to process data import", e);
        }
    }
    
    private void processImportData(Document document, ImportResult result) {
        Element root = document.getDocumentElement();
        NodeList records = root.getElementsByTagName("record");
        
        List<ImportRecord> importRecords = new ArrayList<>();
        
        for (int i = 0; i < records.getLength(); i++) {
            Element record = (Element) records.item(i);
            ImportRecord importRecord = new ImportRecord();
            
            importRecord.setId(getElementValue(record, "id"));
            importRecord.setName(getElementValue(record, "name"));
            importRecord.setCategory(getElementValue(record, "category"));
            
            NodeList nestedElements = record.getChildNodes();
            for (int j = 0; j < nestedElements.getLength(); j++) {
                org.w3c.dom.Node node = nestedElements.item(j);
                if (node.getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                    Element nestedElement = (Element) node;
                    if ("details".equals(nestedElement.getNodeName())) {
                        processDetails(nestedElement, importRecord);
                    } else if ("metadata".equals(nestedElement.getNodeName())) {
                        processMetadata(nestedElement, importRecord);
                    }
                }
            }
            
            importRecords.add(importRecord);
        }
        
        result.setRecords(importRecords);
        result.setTotalRecords(importRecords.size());
        result.setStatus("SUCCESS");
    }
    
    private void processDetails(Element detailsElement, ImportRecord record) {
        NodeList detailNodes = detailsElement.getChildNodes();
        for (int i = 0; i < detailNodes.getLength(); i++) {
            org.w3c.dom.Node node = detailNodes.item(i);
            if (node.getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                Element detail = (Element) node;
                switch (detail.getNodeName()) {
                    case "description":
                        record.setDescription(getElementValue(detail, ""));
                        break;
                    case "quantity":
                        record.setQuantity(Integer.parseInt(getElementValue(detail, "0")));
                        break;
                    case "price":
                        record.setPrice(Double.parseDouble(getElementValue(detail, "0.0")));
                        break;
                }
            }
        }
    }
    
    private void processMetadata(Element metadataElement, ImportRecord record) {
        NodeList metaNodes = metadataElement.getChildNodes();
        for (int i = 0; i < metaNodes.getLength(); i++) {
            org.w3c.dom.Node node = metaNodes.item(i);
            if (node.getNodeType() == org.w3c.dom.Node.ELEMENT_NODE) {
                Element meta = (Element) node;
                switch (meta.getNodeName()) {
                    case "createdDate":
                        record.setCreatedDate(getElementValue(meta, ""));
                        break;
                    case "updatedDate":
                        record.setUpdatedDate(getElementValue(meta, ""));
                        break;
                    case "status":
                        record.setStatus(getElementValue(meta, ""));
                        break;
                }
            }
        }
    }
    
    private String getElementValue(Element parent, String tagName) {
        NodeList nodes = parent.getElementsByTagName(tagName);
        if (nodes.getLength() > 0) {
            return nodes.item(0).getTextContent();
        }
        return "";
    }
    
